# pip install pypdf
from pypdf import PdfReader

reader = PdfReader("annual_report_2025.pdf")
pages = []
for page_num, page in enumerate(reader.pages):
    text = page.extract_text(
        extraction_mode="layout",  # preserves column ordering
        layout_mode_space_vertically=False,
    )
    if text and text.strip():
        pages.append({
            "text": text,
            "page": page_num + 1,      # 1-indexed for humans
            "source": "annual_report_2025.pdf",
        })

print(f"Extracted {len(pages)} non-empty pages")

from bs4 import BeautifulSoup, Tag

def extract_sections(html: str) -> list[dict]:
    """Return list of {heading, text} sections split at h2/h3 boundaries."""
    soup = BeautifulSoup(html, "lxml")
    sections = []
    current_heading = "Introduction"
    current_text = []

    for elem in soup.select("article *"):
        if elem.name in ("h2", "h3"):
            if current_text:
                sections.append({
                    "heading": current_heading,
                    "text": " ".join(current_text),
                })
            current_heading = elem.get_text(strip=True)
            current_text = []
        elif elem.name == "p":
            current_text.append(elem.get_text(strip=True))

    if current_text:
        sections.append({"heading": current_heading, "text": " ".join(current_text)})
    return sections

# pip install python-docx
from docx import Document
from docx.oxml.ns import qn

doc = Document("employee_handbook.docx")
sections = []
current_section = {"heading": "Introduction", "paragraphs": []}

for para in doc.paragraphs:
    style = para.style.name    # e.g. 'Heading 1', 'Heading 2', 'Normal'
    text  = para.text.strip()
    if not text:
        continue

    if style.startswith("Heading"):
        # Save previous section, start new one
        if current_section["paragraphs"]:
            sections.append(current_section)
        current_section = {"heading": text, "paragraphs": [], "style": style}
    else:
        current_section["paragraphs"].append(text)

if current_section["paragraphs"]:
    sections.append(current_section)

# Flatten into Document objects for LangChain
from langchain_core.documents import Document as LC_Doc

lc_docs = []
for sec in sections:
    lc_docs.append(LC_Doc(
        page_content=sec["heading"] + "
" + "
".join(sec["paragraphs"]),
        metadata={"source": "employee_handbook.docx", "section": sec["heading"]},
    ))
